namespace sv_bbd02259abdc46b0b479abd37cdac763.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_bbd02259abdc46b0b479abd37cdac763.Client.Models;

namespace sv_bbd02259abdc46b0b479abd37cdac763.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_bbd02259abdc46b0b479abd37cdac763.Client.Models;
using sv_bbd02259abdc46b0b479abd37cdac763.Client.Services;

namespace sv_bbd02259abdc46b0b479abd37cdac763.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 23, 14, 30, 0, TimeSpan.Zero), Description = "Departed facility", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 8, 15, 0, TimeSpan.Zero), Description = "Arrived at sorting center", Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 16, 0, 0, TimeSpan.Zero), Description = "In transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 22, 45, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 11, 30, 0, TimeSpan.Zero), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero), Description = "Label created", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_bbd02259abdc46b0b479abd37cdac763.Client.Models;

namespace sv_bbd02259abdc46b0b479abd37cdac763.Client.Services;

public sealed class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_bbd02259abdc46b0b479abd37cdac763.Client.Models
@using sv_bbd02259abdc46b0b479abd37cdac763.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<TrackShipment> Logger
@implements IDisposable

<PageTitle>Track Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@(_shipment.EstimatedDelivery?.ToString("f") ?? "N/A")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; <strong>@update.Description</strong> (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

